#include <bits/stdc++.h>
using namespace std;

struct line {
    int to, len;
};

int n, m, a, b;
int v[100005];
int d[200005];
bool vis[200005];
vector<line> l[200005];
queue<int> q;

int main() {
    cin >> n >> m >> a >> b;
    for (int i = 0; i < n; i++) {
        cin >> v[i];
        d[i] = INT_MAX;
    }
    for (int i = 0; i < m; i++) {
        int x, y;
        cin >> x >> y;
        l[x].push_back(line{y, 1});
    }
    d[a] = 0;
    vis[a] = true;
    q.push(a);
    while (!q.empty()) {
        int x = q.front();
        q.pop();
        vis[x] = true;
        for (line i : l[x]) {
            int y = i.to;
            if (d[x] + i.len < d[y]) {
                d[y] = d[x] + i.len;
                if (!vis[y]) {
                    q.push(y);
                }
            }
        }
    }
    if (d[b] == INT_MAX) {
        cout << "No solution";
    }
    else {
        cout << d[b] + v[b] - v[a];
    }
    return 0;
}
